window.ACTIVE_UNIVERSITY='MUJ';window.ACTIVE_PROGRAM='MBA';const currentUrl=window.location.href;if(currentUrl.includes('/online-msc-courses/admission-fee-eligibility-details')){window.ACTIVE_UNIVERSITY="MAHE"}
function isMUJActive(){return(window.ACTIVE_UNIVERSITY==='MUJ'&&window.ACTIVE_PROGRAM==='MBA')}
function normalizeProgram(str){return(str||"").toLowerCase().replace(/[.\s-]+/g,"").trim()}
function filterSectionsByProgram(programName){const selected=normalizeProgram(programName);document.querySelectorAll(".course-fee-section, .admission-process-sect, .eligibility-sect").forEach((section)=>{const sectionProgram=normalizeProgram(section.dataset.program);section.style.display=sectionProgram===selected?"block":"none"})}
function updateScholarshipPopup(courseType){const popup=document.getElementById("scholarship_note_popup");if(!popup)return;popup.setAttribute("data-course",courseType);popup.querySelectorAll(".course-condition").forEach(el=>{if(el.dataset.course==="MAHE"){el.style.display=courseType==="MAHE"?"list-item":"none"}
if(el.dataset.course==="NON_MAHE"){el.style.display=courseType!=="MAHE"?"list-item":"none"}})}
document.addEventListener('DOMContentLoaded',function(){const headers=document.querySelectorAll('.admission-tab-header');const contents=document.querySelectorAll('.admission-tab-content');const scholarship=document.querySelectorAll('.main-scholarship');const params=new URLSearchParams(window.location.search);const universityParam=params.get('university');let tabActivated=!1;headers.forEach(header=>{const tabKey=header.dataset.tab;if(universityParam&&tabKey===universityParam){headers.forEach(h=>h.classList.remove('active'));contents.forEach(c=>c.classList.remove('active'));header.classList.add('active');header.click();const targetTab=document.getElementById('tab-'+tabKey);if(targetTab){targetTab.classList.add('active')}
document.querySelectorAll(".program-tabs").forEach((tab)=>{tab.classList.remove("active");if(tab.dataset.university===universityParam){tab.classList.add("active");const firstProgramBtn=tab.querySelector(".program-tab-btn");if(firstProgramBtn){tab.querySelectorAll(".program-tab-btn").forEach(btn=>btn.classList.remove("active"));firstProgramBtn.classList.add("active");filterSectionsByProgram(firstProgramBtn.dataset.program)}}});tabActivated=!0}
if(currentUrl.includes('/online-msc-courses/subjects')&&universityParam==="MUJ"){const subTabTitle=document.querySelector(".sub-tab-title");const programTabs=document.querySelector(".program-tabs-wrapper");if(subTabTitle)subTabTitle.style.display="none";if(programTabs)programTabs.style.display="none"}});headers.forEach(header=>{header.addEventListener('click',function(){const target=this.dataset.tab;const activeTab=document.getElementById('tab-'+target);const activeScolarship=document.getElementById('scholarship-'+target);window.ACTIVE_UNIVERSITY=this.getAttribute('data-tab');window.ACTIVE_PROGRAM=this.getAttribute('data-program');updateScholarshipPopup(window.ACTIVE_UNIVERSITY);if(!activeScolarship)return;headers.forEach(h=>h.classList.remove('active'));contents.forEach(c=>c.classList.remove('active'));scholarship.forEach(s=>s.classList.remove('active'));this.classList.add('active');if(activeTab){activeTab.classList.add('active')}
activeScolarship.classList.add('active')})});if(currentUrl.includes('/online-msc-courses/subjects')||currentUrl.includes('/online-msc-courses/admission-fee-eligibility-details')){$(document).on('click','.tab-buttons .muj',function(e){const subTabTitle=document.querySelector(".sub-tab-title");const programTabs=document.querySelector(".program-tabs-wrapper");if(subTabTitle)subTabTitle.style.display="none";if(programTabs)programTabs.style.display="none"});$(document).on('click','.tab-buttons .mahe',function(e){const subTabTitle=document.querySelector(".sub-tab-title");const programTabs=document.querySelector(".program-tabs-wrapper");if(subTabTitle)subTabTitle.style.display="block";if(programTabs)programTabs.style.display="block"})}});(function(){function initReadMore(context=document){const boxes=context.querySelectorAll(".read-more-box:not([data-readmore-init])");boxes.forEach(box=>{box.setAttribute("data-readmore-init","true");const fullText=box.textContent.trim();const limit=parseInt(box.dataset.limit)||100;if(fullText.length<=limit)return;const truncateAtWord=(str,limit)=>{const trimmed=str.substring(0,limit);return trimmed.substring(0,trimmed.lastIndexOf(" "))};const visibleText=truncateAtWord(fullText,limit);const hiddenText=fullText.substring(visibleText.length);box.innerHTML=`
        <span class="visible-text">${visibleText}</span>
        <span class="dots">...</span>
        <span class="more-text" style="display:none;">${hiddenText}</span>
        <span class="read-more-link"> Read More</span>
      `;const readMoreLink=box.querySelector(".read-more-link");const moreText=box.querySelector(".more-text");const dots=box.querySelector(".dots");readMoreLink.addEventListener("click",function(){const isExpanded=moreText.style.display==="inline";moreText.style.display=isExpanded?"none":"inline";dots.style.display=isExpanded?"inline":"none";readMoreLink.textContent=isExpanded?" Read More":" Read Less"})})}
document.addEventListener("DOMContentLoaded",function(){initReadMore()});const observer=new MutationObserver(function(mutations){mutations.forEach(mutation=>{mutation.addedNodes.forEach(node=>{if(node.nodeType===1){initReadMore(node)}})})});observer.observe(document.body,{childList:!0,subtree:!0})})();setTimeout(()=>{const firstProgramBtn=document.querySelector(".program-tabs.active .program-tab-btn");if(firstProgramBtn){firstProgramBtn.click()}},50);document.addEventListener("DOMContentLoaded",function(){document.querySelectorAll(".admission-page .admission-tab-header").forEach((btn)=>{btn.addEventListener("click",function(){const university=this.dataset.tab;document.querySelectorAll(".admission-tab-header").forEach((t)=>t.classList.remove("active"));this.classList.add("active");document.querySelectorAll(".program-tabs").forEach((tab)=>{tab.classList.remove("active");if(tab.dataset.university===university){tab.classList.add("active");const firstProgramBtn=tab.querySelector(".program-tab-btn");if(firstProgramBtn){tab.querySelectorAll(".program-tab-btn").forEach(btn=>btn.classList.remove("active"));firstProgramBtn.classList.add("active");filterSectionsByProgram(firstProgramBtn.dataset.program)}}})})});document.querySelectorAll(".syllabus-page .admission-tab-header").forEach((btn)=>{btn.addEventListener("click",function(){const university=this.dataset.tab;document.querySelectorAll(".admission-tab-header").forEach((b)=>b.classList.remove("active"));this.classList.add("active");document.querySelectorAll(".program-tabs").forEach((tab)=>{tab.classList.toggle("active",tab.dataset.university===university)});const firstProgramBtn=document.querySelector(`.program-tabs[data-university="${university}"] .program-tab-btn`);if(firstProgramBtn){firstProgramBtn.click()}})});document.querySelectorAll(".admission-page .program-tab-btn").forEach((btn)=>{btn.addEventListener("click",function(){const programName=this.dataset.program;const parent=this.closest(".program-tabs");parent.querySelectorAll(".program-tab-btn").forEach((b)=>b.classList.remove("active"));this.classList.add("active");filterSectionsByProgram(programName)})});document.querySelectorAll(".syllabus-page .program-tab-btn").forEach((btn)=>{btn.addEventListener("click",function(){const programName=this.dataset.program;const programId=this.dataset.programId;const university=this.dataset.university;const programContent=this.dataset.tab;document.querySelectorAll(".syllabus-page .program-tab-btn").forEach((b)=>b.classList.remove("active"));this.classList.add("active");document.querySelectorAll(".syllabus-page .admission-tab-header").forEach((t)=>{t.classList.toggle("active",t.dataset.tab===university)});window.ACTIVE_UNIVERSITY=university;window.ACTIVE_PROGRAM=programName;updateScholarshipPopup(university);filterSectionsByProgram(programName);document.querySelectorAll(".syllabus-page .program-content-tab").forEach((c)=>c.classList.remove("active"));document.querySelector(".syllabus-page #"+programContent).classList.add("active")})});document.querySelectorAll(".syllabus-page .admission-tab-content .program-content-tab:first-child").forEach((c)=>c.classList.add("active"));$(document).on('click','.section-link',function(e){e.preventDefault();const targetId=$(this).attr('data-id');const candidates=document.querySelectorAll('.active '+targetId);let targetEl=null;candidates.forEach(el=>{const style=window.getComputedStyle(el);if(style.display==='block'){targetEl=el}});if(!targetEl)return;const header=document.querySelector('header');const headerHeight=header?header.offsetHeight:100;const y=targetEl.getBoundingClientRect().top+window.pageYOffset-headerHeight-10;window.scrollTo({top:y,behavior:'smooth'})})});document.addEventListener("click",function(e){const btn=e.target.closest(".show-popup");if(!btn)return;const popupId=btn.dataset.showpopup;const popup=document.getElementById(popupId);if(!popup)return;popup.classList.remove("hidden");updateScholarshipPopup(window.ACTIVE_UNIVERSITY)})